var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"어렸을 적의 아버지께선 제가 넘어져도 그저 지켜만 볼 뿐, 손을 잡아주지 않으셨어요.","JPN":" まだ小さかった頃、お父様は私が転んでもただ見ているだけで手を取ってくれませんでした。","ENG":" When I was younger, I would trip, and my father would never hold my hand or help me up. He would just watch.","TWN":"我記得小時候，當我跌倒時，父親只會在一旁看，不會伸手扶我起來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그때의 무지하고 어리석었던 전 그런 아버지가 무정하다고 생각했죠.","JPN":" 当時無知で愚かだった私は、そんなお父様を思いやりのない人だと思っていました。","ENG":" I was ignorant and foolish enough to think that my father was heartless.","TWN":"那時候的我還小不懂事，認為父親很冷酷無情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"지금도 그렇게 느끼냐고요?","JPN":" 今もそう思っているかって？","ENG":" Do I still feel that way?","TWN":"我現在還這麼認為嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아뇨, 그럴 리가요.","JPN":" いいえ、そんなわけありません。","ENG":" No, of course not.","TWN":"當然不會，怎麼可能？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아버지는 누구보다 절 소중히 여기시는 분이세요. 그래서 무지한 제가 배움을 얻길 원하신 거죠.","JPN":" お父様は誰よりも私のことを大事に思ってくださる方です。ですから無知な私に学んでほしかったのでしょう。","ENG":" He cherishes me more than anything. Which is why he wanted me to learn.","TWN":"父親是這個世界上最珍惜我的人，他只是希望我能夠學到教訓而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그 시절의 나약한 몸을 가졌던 저에겐… 누군가의 도움을 받아 일어선다는 결과보다, 스스로 일어나는 법을 배우는 과정이 중요했으니까요.","JPN":" 当時身体の弱かった私には……誰かの助けを借りて立ち上がれたという結果より、自分で立ち上がる方法を学んでいく過程が重要だったのですから。","ENG":" For a weak child... the process of learning how to get up by myself was more important than the outcome of getting up with someone else's help.","TWN":"對那時候還很弱小的我而言…比起別人扶我起來的結果，學習自己爬起來的過程更重要。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"결과라는 건 어차피 정해져 있는 거예요. 중요한 건 거기까지 다다르는 과정에서 얻는 것들이죠.","JPN":" 結果というものはどうせ決まっているものです。大事なのは、そこへたどり着くまでの過程で何を得るかです。","ENG":" Outcomes are predetermined. What's important is what you earn from the process of getting there.","TWN":"結果是注定好的，重要的是爬起來的過程中學到的東西。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그게 제가 당신을 좋아하는 이유랍니다.","JPN":" そして、私があなたを好きな理由はそこにあります。","ENG":" That's why I like you.","TWN":"這就是我為什麼會喜歡你的原因。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"당신은 결과가 아닌 과정을 지켜보는 게 더 흥미로운 사람이거든요.","JPN":" あなたは結果ではなく、過程を見守ることに興味を感じる人ですから。","ENG":" It's more interesting to watch your process than your outcome.","TWN":"因為你看重的不是結果，而是過程。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그것이 성공이든 파멸이든, 당신은 언제나 뜻밖의 방식으로 그 뻔한 결과를 이끌어내니까요.","JPN":" それが成功であれ破滅であれ、あなたはわかり切った結果をいつも思いがけないやり方で引き出してくるんです。","ENG":" Whether it be success or destruction, you come to that result through unpredictable means.","TWN":"無論是成功或失敗，你總是用意料之外的方法帶出顯而易見的結果。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그러니 걱정마세요.","JPN":" ですから、心配しないでください。","ENG":" So don't worry.","TWN":"所以你放心，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"당신의 삶이 결말에 다다르기 전까지, 전 계속 당신 곁에 머물 테니까요.","JPN":" あなたの生が結末にたどり着くまで、私はずっとあなたのそばにいます。","ENG":" I will stay by your side until you see the outcome of your life.","TWN":"在你的人生走到盡頭之前，我會一直待在你身邊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};